const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const bcrypt = require('bcrypt');
const { deleteUser } = require('./userModel'); // Assume this is a function that deletes a user from the database

const app = express();

app.use(bodyParser.json());
app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: true, httpOnly: true, maxAge: 60000 }
}));

// Middleware to check if user is authenticated
function isAuthenticated(req, res, next) {
  if (req.session && req.session.userId) {
    return next();
  } else {
    res.status(401).json({ error: 'Unauthorized' });
  }
}

app.post('/delete-account', isAuthenticated, async (req, res) => {
  const { password } = req.body;
  const userId = req.session.userId;

  if (!password) {
    return res.status(400).json({ error: 'Password is required' });
  }

  try {
    const user = await getUserById(userId); // Assume this function fetches user by ID
    const match = await bcrypt.compare(password, user.passwordHash);

    if (!match) {
      return res.status(403).json({ error: 'Incorrect password' });
    }

    await deleteUser(userId);
    req.session.destroy(err => {
      if (err) {
        return res.status(500).json({ error: 'Failed to delete account' });
      }
      res.status(200).json({ message: 'Account deleted successfully' });
    });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

